import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from "framer-motion";
import axios from 'axios';
import RegistroEmpresa from './registroEmpresa';

const EmpresasPanel = ({ loggedInUser }) => {
  // Estados para datos
  const [fullEmpresas, setFullEmpresas] = useState([]);
  const [empresas, setEmpresas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [ordenAntiguedad, setOrdenAntiguedad] = useState('asc');
  const [filtroActivo, setFiltroActivo] = useState(null);
  const [selectedEmpresa, setSelectedEmpresa] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [modalEditable, setModalEditable] = useState(false);
  const [loading, setLoading] = useState(true);
  const [showRegistroModal, setShowRegistroModal] = useState(false);
  const [showCrearModal, setShowCrearModal] = useState(false);
  const [nuevoEmpresaData, setNuevoEmpresaData] = useState({
    denominacion_social: '',
    nombre_comercial: '',
    fecha_fundacion: '',
    nit: '',
    vision: '',
    mision: '',
    descripcion: '',
    url: '',
    direccion_web: '',
    id_actividad: '',
    id_tamanio: '',
  });
  const [actividades, setActividades] = useState([]);
  const [tamanios, setTamanios] = useState([]);
  const [rubrosDisponibles, setRubrosDisponibles] = useState([]);

  // Base URL para Cloudinary
  const CLOUDINARY_BASE_URL = 'https://res.cloudinary.com/diswqpy8v/image/upload';

  // Roles para edición
  const esAdmin = loggedInUser?.id_rol === 1;
  const esColaborador = loggedInUser?.id_rol === 2;
  const puedeEditar = esAdmin || esColaborador;

  const recargarEmpresas = async () => {
    try {
      const { data } = await axios.get('http://localhost:3000/empresas/resumen');
      const mapped = data.map(mapEmpresaResumen);
      setFullEmpresas(mapped);
      setEmpresas(mapped);
    } catch (error) {
      console.error('Error recargando empresas:', error);
    }
  };

  // Mapear respuesta del API para resumen
  const mapEmpresaResumen = e => ({
    id: e.id_empresa,
    nombre: e.nombre_comercial,
    rubro: e.nombre_actividad || '',
    descripcion_actividad: e.descripcion_actividad || '',
    slogan: e.vision || '',
    descripcion: e.descripcion || '',
    fecha_fundacion: e.fecha_fundacion || '',
    fundacion: e.fecha_fundacion ? new Date(e.fecha_fundacion).getFullYear() : '',
    sede: e.sedes?.[0]?.ciudad || '',
    departamento: e.sedes?.[0]?.departamento || '',
    empleados: e.nombre_tamanio || '',
    sitioWeb: e.direccion_web || '',
    imagen: e.urlLogo
      ? (e.urlLogo.startsWith('http') ? e.urlLogo : `${CLOUDINARY_BASE_URL}/${e.urlLogo}`)
      : 'https://via.placeholder.com/300.png?text=Sin+Imagen',
    tienePremios: e.premios?.length > 0 || false,
    rubros: e.rubros || [],
    operacionesInternacionales: e.operaciones_internacionales || [],
    familia: e.familia || [],
    premios: e.premios || [],
    id_actividad: e.id_actividad || 0,
    id_tamanio: e.id_tamanio || 0
  });

  // Fetch inicial de empresas y rubros
  useEffect(() => {
    const fetchEmpresas = async () => {
      try {
        const { data } = await axios.get('http://localhost:3000/empresas/resumen');
        const mapped = data.map(mapEmpresaResumen);
        setFullEmpresas(mapped);
        setEmpresas(mapped);
      } catch (error) {
        console.error('Error al cargar empresas:', error);
      } finally {
        setLoading(false);
      }
    };

    const fetchRubros = async () => {
      try {
        const { data } = await axios.get('http://localhost:3000/rubros');
        if (Array.isArray(data)) {
          setRubrosDisponibles(data);
        } else {
          setRubrosDisponibles([]);
        }
      } catch (error) {
        console.error('Error al cargar rubros:', error);
        setRubrosDisponibles([]);
      }
    };

    fetchEmpresas();
    fetchRubros();
  }, []);

  // Cargar actividades y tamanios para los combos en la creación
  useEffect(() => {
    const fetchActividades = async () => {
      try {
        const { data } = await axios.get('http://localhost:3000/actividades');
        setActividades(data);
      } catch (error) {
        console.error('Error cargando actividades:', error);
      }
    };
    const fetchTamanios = async () => {
      try {
        const { data } = await axios.get('http://localhost:3000/tamanios');
        setTamanios(data);
      } catch (error) {
        console.error('Error cargando tamaños:', error);
      }
    };
    fetchActividades();
    fetchTamanios();
  }, []);

  // Manejar cambios en formulario creación
  const handleNuevoChange = (e) => {
    const { name, value } = e.target;
    setNuevoEmpresaData(prev => ({ ...prev, [name]: value }));
  };

  const handleCrearEmpresa = async (e) => {
    e.preventDefault();

    if (!nuevoEmpresaData.denominacion_social.trim()) {
      alert('Denominación social es obligatoria');
      return;
    }
    if (!nuevoEmpresaData.nit || isNaN(Number(nuevoEmpresaData.nit))) {
      alert('NIT válido es obligatorio');
      return;
    }
    if (!nuevoEmpresaData.fecha_fundacion) {
      alert('Fecha de fundación es obligatoria');
      return;
    }
    if (!nuevoEmpresaData.id_actividad) {
      alert('Selecciona una actividad');
      return;
    }
    if (!nuevoEmpresaData.id_tamanio) {
      alert('Selecciona un tamaño');
      return;
    }

    try {
      const payload = {
        ...nuevoEmpresaData,
        id_usuario: loggedInUser.id_usuario,
        fecha_fundacion: new Date(nuevoEmpresaData.fecha_fundacion).toISOString(),
        nit: Number(nuevoEmpresaData.nit),
        id_actividad: Number(nuevoEmpresaData.id_actividad),
        id_tamanio: Number(nuevoEmpresaData.id_tamanio),
      };

      await axios.post('http://localhost:3000/ingresarEmpresa', payload);
      setShowCrearModal(false);
      const { data } = await axios.get('http://localhost:3000/empresas/resumen');
      setFullEmpresas(data.map(mapEmpresaResumen));
      setEmpresas(data.map(mapEmpresaResumen));
    } catch (error) {
      console.error('Error creando empresa:', error);
      alert('Error al crear empresa. Intenta nuevamente.');
    }
  };

  // Filtrar y ordenar
  useEffect(() => {
    let lista = [...fullEmpresas];
    const term = busqueda.trim().toLowerCase();

    if (term) {
      lista = lista.filter(e =>
        (e.nombre || '').toLowerCase().includes(term) ||
        (e.rubro || '').toLowerCase().includes(term) ||
        (e.departamento || '').toLowerCase().includes(term)
      );
    }

    lista.sort((a, b) => {
      const dateA = a.fecha_fundacion ? new Date(a.fecha_fundacion) : new Date(0);
      const dateB = b.fecha_fundacion ? new Date(b.fecha_fundacion) : new Date(0);
      return ordenAntiguedad === 'asc' ? dateA - dateB : dateB - dateA;
    });

    setEmpresas(lista);
  }, [fullEmpresas, busqueda, ordenAntiguedad]);

  // Manejar filtros
  const aplicarFiltro = (tipoFiltro) => {
    if (filtroActivo === tipoFiltro) {
      setEmpresas(fullEmpresas);
      setFiltroActivo(null);
      return;
    }

    setFiltroActivo(tipoFiltro);

    if (tipoFiltro === '50años') {
      const añoActual = new Date().getFullYear();
      const empresas50 = fullEmpresas.filter(e => añoActual - e.fundacion > 50);
      const otrasEmpresas = fullEmpresas.filter(e => añoActual - e.fundacion <= 50);
      setEmpresas(empresas50.concat(otrasEmpresas));
    }
    else if (tipoFiltro === 'premio') {
      const conPremios = fullEmpresas.filter(e => e.tienePremios);
      const sinPremios = fullEmpresas.filter(e => !e.tienePremios);
      setEmpresas(conPremios.concat(sinPremios));
    }
    else if (tipoFiltro === 'rubro') {
      const agrupadasPorRubro = fullEmpresas.reduce((acc, empresa) => {
        const rubro = empresa.rubro || 'Sin rubro';
        if (!acc[rubro]) acc[rubro] = [];
        acc[rubro].push(empresa);
        return acc;
      }, {});
      const listaAgrupada = Object.values(agrupadasPorRubro).flat();
      setEmpresas(listaAgrupada);
    }
    else if (tipoFiltro === 'departamento') {
      const agrupadasPorDepto = fullEmpresas.reduce((acc, empresa) => {
        const depto = empresa.departamento || 'Sin departamento';
        if (!acc[depto]) acc[depto] = [];
        acc[depto].push(empresa);
        return acc;
      }, {});
      const listaAgrupada = Object.values(agrupadasPorDepto).flat();
      setEmpresas(listaAgrupada);
    }
  };

  // Abrir modal detalle solo lectura
  const openModal = async (empresa) => {
    try {
      const { data } = await axios.get(`http://localhost:3000/empresa/${empresa.id}`);
      setSelectedEmpresa({
        id: data.id_empresa,
        denominacion_social: data.denominacion_social || '',
        nombre: data.nombre_comercial || '',
        slogan: data.vision || '',
        descripcion: data.descripcion || '',
        rubro: data.nombre_actividad || '',
        id_actividad: data.id_actividad || 0,
        descripcion_actividad: data.descripcion_actividad || '',
        fundacion: data.fecha_fundacion ? new Date(data.fecha_fundacion).getFullYear() : '',
        sede: data.sedes?.[0]?.ciudad || '',
        departamento: data.sedes?.[0]?.departamento || '',
        empleados: data.nombre_tamanio || '',
        sitioWeb: data.direccion_web || '',
        imagen: data.urlLogo ? (data.urlLogo.startsWith('http') ? data.urlLogo : `${CLOUDINARY_BASE_URL}/${data.urlLogo}`) : 'https://via.placeholder.com/300.png?text=Sin+Imagen',
        premios: data.premios || [],
        rubros: data.rubros || [],
        operacionesInternacionales: data.operaciones_internacionales || [],
        familia: data.familia || [],
        id_tamano: data.id_tamano || 0
      });
      setModalEditable(false);
      setShowModal(true);
    } catch (error) {
      console.error('Error al cargar detalles de la empresa:', error);
    }
  };

  // Abrir modal editable
  const openModalEditable = async (empresa) => {
    try {
      const { data } = await axios.get(`http://localhost:3000/empresa/${empresa.id}`);
      setSelectedEmpresa({
        id: data.id_empresa,
        denominacion_social: data.denominacion_social || '',
        nombre: data.nombre_comercial || '',
        slogan: data.vision || '',
        descripcion: data.descripcion || '',
        rubro: data.nombre_actividad || '',
        id_actividad: data.id_actividad || 0,
        descripcion_actividad: data.descripcion_actividad || '',
        fundacion: data.fecha_fundacion ? new Date(data.fecha_fundacion).getFullYear() : '',
        sede: data.sedes?.[0]?.ciudad || '',
        departamento: data.sedes?.[0]?.departamento || '',
        empleados: data.nombre_tamanio || '',
        sitioWeb: data.direccion_web || '',
        imagen: data.urlLogo ? (data.urlLogo.startsWith('http') ? data.urlLogo : `${CLOUDINARY_BASE_URL}/${data.urlLogo}`) : '',
        premios: data.premios || [],
        rubros: data.rubros || [],
        operacionesInternacionales: data.operaciones_internacionales || [],
        familia: data.familia || [],
        id_tamano: data.id_tamano || 0
      });
      setModalEditable(true);
      setShowModal(true);
    } catch (error) {
      console.error('Error al cargar detalles de la empresa para editar:', error);
    }
  };

  const closeModal = () => {
    setShowModal(false);
    setSelectedEmpresa(null);
  };

  const handleGuardarCambios = async (empresaEditada) => {
    try {
      setLoading(true);

      if (!empresaEditada.denominacion_social || empresaEditada.denominacion_social.trim() === '') {
        alert("Debe ingresar la denominación social.");
        setLoading(false);
        return;
      }

      if (!empresaEditada.nit || empresaEditada.nit === 0) {
        alert("Debe ingresar un NIT válido.");
        setLoading(false);
        return;
      }

      if (!empresaEditada.id) {
        alert("No se encontró el ID de la empresa para actualizar.");
        setLoading(false);
        return;
      }

      const payload = {
        id_usuario: loggedInUser.id_usuario || 0,
        denominacion_social: empresaEditada.denominacion_social.trim(),
        nombre_comercial: empresaEditada.nombre || '',
        fecha_fundacion: empresaEditada.fundacion ? new Date(empresaEditada.fundacion, 0, 1).toISOString() : null,
        nit: empresaEditada.nit,
        vision: empresaEditada.slogan || '',
        mision: empresaEditada.mision?.trim() || "No disponible",
        descripcion: empresaEditada.descripcion || '',
        url: empresaEditada.url?.trim() || "http://example.com",
        direccion_web: empresaEditada.sitioWeb || '',
        id_actividad: empresaEditada.id_actividad || 1,
        id_tamanio: empresaEditada.id_tamanio || 1,
      };

      await axios.put(`http://localhost:3000/actualizarEmpresa/${empresaEditada.id}`, payload);

      setFullEmpresas(prev => prev.map(e => e.id === empresaEditada.id ? {...e, ...empresaEditada} : e));
      setEmpresas(prev => prev.map(e => e.id === empresaEditada.id ? {...e, ...empresaEditada} : e));

      setShowModal(false);
    } catch (error) {
      console.error('Error al guardar cambios:', error);
      alert("Error al guardar los cambios. Intenta nuevamente.");
    } finally {
      setLoading(false);
    }
  };

  const visitarSitio = () => {
    if (!selectedEmpresa?.sitioWeb) return;
    const url = selectedEmpresa.sitioWeb.startsWith('http')
      ? selectedEmpresa.sitioWeb
      : `https://${selectedEmpresa.sitioWeb}`;
    window.open(url, '_blank');
  };

  // EditableEmpresaModal - relaciones NO editables, solo mostrar como texto + ocultos para id_actividad y id_tamano
  const EditableEmpresaModal = ({ empresa, onClose, onSave }) => {
    const [formData, setFormData] = useState({ ...empresa });

    useEffect(() => {
      setFormData({ ...empresa });
    }, [empresa]);

    const handleChange = (e) => {
      const { name, value } = e.target;
      if (name === 'id_actividad' || name === 'id_tamano') return;
      setFormData(prev => ({
        ...prev,
        [name]: value,
      }));
    };

    const handleSubmit = (e) => {
      e.preventDefault();
      onSave(formData);
    };

    return (
      <form onSubmit={handleSubmit} className="text-left max-w-2xl mx-auto px-5">
        <h2 className="mb-8 font-bold text-2xl text-primary text-center uppercase tracking-wider font-bodoni">
          Modo de Edición
        </h2>

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Denominación Social:
        </label>
        <input
          name="denominacion_social"
          type="text"
          value={formData.denominacion_social}
          onChange={handleChange}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
          required
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Nombre Comercial:
        </label>
        <input
          name="nombre"
          type="text"
          value={formData.nombre}
          onChange={handleChange}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
          required
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Eslogan / Visión:
        </label>
        <input
          name="slogan"
          type="text"
          value={formData.slogan}
          onChange={handleChange}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Descripción:
        </label>
        <textarea
          name="descripcion"
          value={formData.descripcion}
          onChange={handleChange}
          rows={3}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Rubro (actividad):
        </label>
        <input
          type="text"
          value={formData.rubro || ''}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles bg-gray-100 text-gray-500 cursor-not-allowed"
          disabled
          title="Campo no editable"
        />
        <input
          type="hidden"
          name="id_actividad"
          value={formData.id_actividad || 0}
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Tamaño (Empleados):
        </label>
        <input
          type="text"
          value={formData.empleados || ''}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles bg-gray-100 text-gray-500 cursor-not-allowed"
          disabled
          title="Campo no editable"
        />
        <input
          type="hidden"
          name="id_tamano"
          value={formData.id_tamano || 0}
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Actividad:
        </label>
        <textarea
          name="descripcion_actividad"
          value={formData.descripcion_actividad}
          onChange={handleChange}
          rows={2}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Año Fundación:
        </label>
        <input
          name="fundacion"
          type="number"
          value={formData.fundacion}
          onChange={handleChange}
          min="1800"
          max={new Date().getFullYear()}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Sede (Ciudad):
        </label>
        <input
          name="sede"
          type="text"
          value={formData.sede}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles bg-gray-100 text-gray-500 cursor-not-allowed"
          disabled
          title="Campo no editable"
          readOnly
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Departamento:
        </label>
        <input
          name="departamento"
          type="text"
          value={formData.departamento}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles bg-gray-100 text-gray-500 cursor-not-allowed"
          disabled
          title="Campo no editable"
          readOnly
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Sitio Web:
        </label>
        <input
          name="sitioWeb"
          type="text"
          value={formData.sitioWeb}
          onChange={handleChange}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          NIT:
        </label>
        <input
          name="nit"
          type="number"
          value={formData.nit || ''}
          onChange={handleChange}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
          required
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          URL (opcional):
        </label>
        <input
          name="url"
          type="text"
          value={formData.url || ''}
          onChange={handleChange}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
        />

        <label className="block text-text-main text-sm font-bold mb-1.5 mt-4 font-bodoni">
          Misión:
        </label>
        <textarea
          name="mision"
          value={formData.mision || ''}
          onChange={handleChange}
          rows={2}
          className="w-full mb-3.5 px-3.5 py-2.5 text-base rounded-lg border-2 border-gray-300 box-border font-miles transition-colors duration-300 focus:border-accent focus:outline-none"
        />

        <div className="flex justify-between mt-7">
          <button
            type="button"
            onClick={onClose}
            className="px-6 py-3 rounded-lg font-bold text-sm cursor-pointer transition-colors duration-300 border-none min-w-[120px] bg-gray-400 text-gray-800 hover:bg-gray-500 font-bodoni"
          >
            Cancelar
          </button>
          <button
            type="submit"
            className="px-6 py-3 rounded-lg font-bold text-sm cursor-pointer transition-colors duration-300 border-none min-w-[120px] bg-primary text-white hover:bg-opacity-80 font-bodoni"
          >
            Guardar
          </button>
        </div>
      </form>
    );
  };

  // Modal solo lectura
  const DetalleEmpresaModal = ({ empresa, onClose }) => {
    const visitarSitio = () => {
      const url = empresa.sitioWeb.startsWith('http') ? empresa.sitioWeb : `https://${empresa.sitioWeb}`;
      window.open(url, '_blank');
    };

    const fadeIn = {
      initial: { opacity: 0, y: 10 },
      animate: { opacity: 1, y: 0 },
      transition: { duration: 0.3 }
    };

    return (
      <>
        <div className="flex justify-between items-center mb-6 p-6 border-b border-stroke">
          <motion.h2 
            className="text-2xl font-bold text-primary font-bodoni"
            whileHover={{ scale: 1.03 }}
          >
            {empresa.nombre}
          </motion.h2>
          <motion.button
            className="text-3xl text-text-muted hover:text-primary transition-colors duration-200 cursor-pointer"
            onClick={onClose}
            whileHover={{ scale: 1.2 }}
          >
            ×
          </motion.button>
        </div>

        <div className="flex gap-4 p-6">
          <div className="flex-1">
            <motion.h3 
              className="text-lg font-semibold text-primary mb-4 font-bodoni"
              whileHover={{ scale: 1.03 }} 
              {...fadeIn}
            >
              {empresa.slogan}
            </motion.h3>

            <motion.p 
              className="text-text-main mb-4 leading-relaxed font-miles"
              {...fadeIn}
            >
              {empresa.descripcion}
            </motion.p>

            <div className="space-y-2">
              <motion.p 
                className="text-sm text-text-main font-miles"
                {...fadeIn} 
                whileHover={{ scale: 1.02 }}
              >
                <strong className="text-primary font-bodoni">Rubro:</strong> {empresa.rubro}
              </motion.p>

              {empresa.descripcion_actividad && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Actividad:</strong> {empresa.descripcion_actividad}
                </motion.p>
              )}

              <motion.p 
                className="text-sm text-text-main font-miles"
                {...fadeIn} 
                whileHover={{ scale: 1.02 }}
              >
                <strong className="text-primary font-bodoni">Fundación:</strong> {empresa.fundacion}
              </motion.p>

              {empresa.sede && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Sede:</strong> {empresa.sede}
                </motion.p>
              )}

              {empresa.departamento && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Departamento:</strong> {empresa.departamento}
                </motion.p>
              )}

              {empresa.empleados && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Tamaño:</strong> {empresa.empleados}
                </motion.p>
              )}

              {empresa.sitioWeb && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Sitio web:</strong> {empresa.sitioWeb}
                </motion.p>
              )}

              {empresa.rubros?.length > 0 && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Rubros adicionales:</strong> {empresa.rubros.join(', ')}
                </motion.p>
              )}

              {empresa.operacionesInternacionales?.length > 0 && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Operaciones internacionales:</strong> {empresa.operacionesInternacionales.join(', ')}
                </motion.p>
              )}

              {empresa.familia?.length > 0 && (
                <motion.p 
                  className="text-sm text-text-main font-miles"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Familiar:</strong> Sí ({empresa.familia.length} registros)
                </motion.p>
              )}

              {empresa.premios?.length > 0 && (
                <motion.div 
                  className="mt-4"
                  {...fadeIn} 
                  whileHover={{ scale: 1.02 }}
                >
                  <strong className="text-primary font-bodoni">Premios:</strong>
                  <ul className="mt-2 ml-4 space-y-1">
                    {empresa.premios.map((premio, idx) => (
                      <li key={idx} className="text-sm text-text-main font-miles">
                        {premio.entidad_otorgadora} ({premio.anio}) - {premio.descripcion} ({premio.tipo})
                      </li>
                    ))}
                  </ul>
                </motion.div>
              )}
            </div>
          </div>
        </div>

        <div className="flex justify-end gap-2.5 p-6 border-t border-stroke">
          {empresa.sitioWeb && (
            <motion.button
              className="bg-accent text-primary px-4 py-2 rounded-lg font-bold text-sm hover:bg-opacity-80 transition-colors duration-200 font-bodoni"
              onClick={visitarSitio}
              whileHover={{ scale: 1.1 }}
            >
              Visitar sitio web
            </motion.button>
          )}
          <motion.button
            className="bg-primary text-white px-4 py-2 rounded-lg font-bold text-sm hover:bg-opacity-80 transition-colors duration-200 font-bodoni"
            onClick={() => window.location.href = `mailto:info@desconocido.com`}
            whileHover={{ scale: 1.1 }}
          >
            Contactar
          </motion.button>
        </div>
      </>
    );
  };

  // Renderizar empresas con botón editar si puede
  const renderEmpresas = () => {
    return empresas.map((e, i) => (
      <motion.div
        key={e.id}
        className="bg-white rounded-lg shadow-lg overflow-hidden cursor-pointer hover:shadow-xl transition-shadow duration-300 relative group"
        onClick={() => openModal(e)}
        whileHover={{ scale: 1.05 }}
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, delay: i * 0.1 }}
      >
        <div className="relative h-48 bg-gradient-to-br from-primary to-accent flex items-center justify-center">
          <div className="text-white text-center font-bold text-lg font-bodoni px-4">
            {e.nombre}
          </div>
          <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-30 transition-all duration-300 flex items-center justify-center">
            <div className="text-white text-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
              <div className="font-bold text-lg font-bodoni mb-1">{e.nombre}</div>
              <div className="text-sm font-miles">{e.rubro}</div>
              <div className="text-xs font-miles italic">{e.slogan}</div>
            </div>
          </div>
          {puedeEditar && (
            <button
              onClick={(ev) => {
                ev.stopPropagation();
                openModalEditable(e);
              }}
              className="absolute top-2 right-2 bg-white bg-opacity-30 border-none rounded text-white px-2.5 py-1 cursor-pointer font-bold text-sm hover:bg-opacity-50 transition-all duration-200 font-bodoni"
              title="Editar empresa"
            >
              Editar
            </button>
          )}
        </div>
      </motion.div>
    ));
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="text-xl text-primary font-bodoni">Cargando empresas...</div>
      </div>
    );
  }

  return (
    <motion.div 
      className="w-4/5 mx-auto my-16 box-border h-[65vh]"
      initial={{ opacity: 0 }} 
      animate={{ opacity: 1 }} 
      transition={{ duration: 0.5 }}
    >
      {/* BARRA SUPERIOR */}
      <div className="flex items-center justify-between bg-primary px-3 py-2 rounded-t-lg mx-auto max-w-full box-border">
        <div className="flex-1 flex justify-center">
          <div className="relative flex-1 flex justify-center">
            <input
              type="text"
              placeholder="Buscar empresa..."
              value={busqueda}
              onChange={e => setBusqueda(e.target.value)}
              className="w-4/5 px-3 py-2 rounded-full border border-gray-300 outline-none text-sm h-full font-miles bg-white bg-opacity-60 focus:bg-opacity-80 transition-all duration-200"
            />
            <span className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500">🔍</span>
          </div>
        </div>
        <div className="flex-1 flex justify-end">
          {/* Espacio para futuros controles */}
        </div>
      </div>

      {/* PANEL PRINCIPAL */}
      <div className="flex gap-0">
        <div className="w-1/4 bg-surface p-4 rounded-bl-lg">
          <img 
            src="/media/empresasPage/bolivia.jpg" 
            alt="Imagen lateral" 
            className="w-full h-auto rounded-lg"
          />
          {loggedInUser?.id_rol === 1 && (
            <>
              <button
                className="w-full mt-2.5 bg-primary text-white rounded-md py-2.5 px-5 font-bold cursor-pointer border-none hover:bg-opacity-80 transition-colors duration-200 font-bodoni"
                onClick={() => setShowRegistroModal(true)}
                title="Crear nueva empresa"
              >
                Añadir empresa
              </button>

              {showRegistroModal && (
                <div 
                  className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-[9999]"
                  onClick={() => setShowRegistroModal(false)}
                >
                  <div 
                    className="bg-white rounded-lg max-w-2xl w-[90%] max-h-[90vh] overflow-y-auto p-5"
                    onClick={(e) => e.stopPropagation()}
                  >
                    <RegistroEmpresa 
                      onRegistroExitoso={() => {
                        setShowRegistroModal(false);
                        recargarEmpresas();
                      }}
                    />
                  </div>
                </div>
              )}
            </>
          )}
        </div>

        <div className="flex-1 bg-background p-6 rounded-br-lg">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {renderEmpresas()}
          </div>
        </div>
      </div>

      {/* MODAL */}
      <AnimatePresence>
        {showModal && selectedEmpresa && (
          <motion.div 
            className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"
            onClick={closeModal} 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
          >
            <motion.div 
              className="bg-white rounded-lg max-w-4xl w-[90%] max-h-[90vh] overflow-y-auto shadow-2xl"
              onClick={e => e.stopPropagation()} 
              initial={{ scale: 0.8, opacity: 0 }} 
              animate={{ scale: 1, opacity: 1 }} 
              exit={{ scale: 0.8, opacity: 0 }} 
              transition={{ duration: 0.3 }}
            >
              {modalEditable ? (
                <EditableEmpresaModal
                  empresa={selectedEmpresa}
                  onClose={closeModal}
                  onSave={handleGuardarCambios}
                />
              ) : (
                <DetalleEmpresaModal
                  empresa={selectedEmpresa}
                  onClose={closeModal}
                />
              )}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default EmpresasPanel;
